import{_ as t,o as a,c as n,a2 as s}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Human-in-the-Loop Patterns for Coding Agents","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/human-in-the-loop/index.md","filePath":"research/concepts/human-in-the-loop/index.md"}'),o={name:"research/concepts/human-in-the-loop/index.md"};function r(i,e,d,l,p,h){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="human-in-the-loop-patterns-for-coding-agents" tabindex="-1">Human-in-the-Loop Patterns for Coding Agents <a class="header-anchor" href="#human-in-the-loop-patterns-for-coding-agents" aria-label="Permalink to &quot;Human-in-the-Loop Patterns for Coding Agents&quot;">вҖӢ</a></h1><blockquote><p>Research into how AI coding agents balance autonomy with human oversightвҖ”the mechanisms, trade-offs, and design principles that keep humans in control without destroying productivity.</p></blockquote><hr><h2 id="why-human-in-the-loop-matters" tabindex="-1">Why Human-in-the-Loop Matters <a class="header-anchor" href="#why-human-in-the-loop-matters" aria-label="Permalink to &quot;Why Human-in-the-Loop Matters&quot;">вҖӢ</a></h2><p>AI coding agents can read files, write code, execute shell commands, manage git repos, and interact with external services. This power creates real risk:</p><ol><li><p><strong>Agents are powerful but fallible.</strong> LLMs hallucinate. They misinterpret intent. They confidently execute the wrong plan. A single bad <code>rm -rf</code> or <code>git push --force</code> can cause irreversible damage that no amount of clever prompting can undo.</p></li><li><p><strong>Irreversible actions demand oversight.</strong> File deletion, git operations, network requests, package installations, and database mutations are all actions where the cost of a mistake vastly exceeds the cost of a confirmation prompt.</p></li><li><p><strong>Users must maintain agency and understanding.</strong> If an agent makes 50 changes across 12 files without explanation, the user loses the ability to review, learn, or debug. The human becomes a passenger, not a pilot.</p></li><li><p><strong>Trust must be earned progressively.</strong> A new user should not be asked to grant blanket permissions. Trust should ratchet up as the agent demonstrates competence in the current contextвҖ”and ratchet back down when the context changes.</p></li><li><p><strong>Compliance and safety requirements.</strong> Enterprise environments require audit trails, policy enforcement, and the ability to prove that a human approved critical actions. Headless automation needs different guardrails than interactive sessions.</p></li></ol><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Risk without HITL:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  User: &quot;Clean up this project&quot;</span></span>
<span class="line"><span>  Agent: rm -rf node_modules/ &amp;&amp; rm -rf .git/ &amp;&amp; rm -rf src/legacy/</span></span>
<span class="line"><span>  Result: Irreversible data loss, no undo possible</span></span></code></pre></div><hr><h2 id="the-spectrum-of-human-involvement" tabindex="-1">The Spectrum of Human Involvement <a class="header-anchor" href="#the-spectrum-of-human-involvement" aria-label="Permalink to &quot;The Spectrum of Human Involvement&quot;">вҖӢ</a></h2><p>Human-in-the-loop is not binary. It exists on a spectrum:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Full Manual     Supervised       Guided          Monitored        Full</span></span>
<span class="line"><span>Control         Autonomy         Autonomy        Autonomy         Autonomy</span></span>
<span class="line"><span>    в”Ӯ               в”Ӯ               в”Ӯ               в”Ӯ               в”Ӯ</span></span>
<span class="line"><span>    в–ј               в–ј               в–ј               в–ј               в–ј</span></span>
<span class="line"><span>в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ   в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ   в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ   в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ   в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ</span></span>
<span class="line"><span>в”Ӯ Human   в”Ӯ   в”Ӯ Agent   в”Ӯ   в”Ӯ Agent   в”Ӯ   в”Ӯ Agent   в”Ӯ   в”Ӯ Agent   в”Ӯ</span></span>
<span class="line"><span>в”Ӯ types   в”Ӯ   в”Ӯ suggestsв”Ӯ   в”Ӯ plans,  в”Ӯ   в”Ӯ acts,   в”Ӯ   в”Ӯ acts    в”Ӯ</span></span>
<span class="line"><span>в”Ӯ every   в”Ӯ   в”Ӯ human   в”Ӯ   в”Ӯ human   в”Ӯ   в”Ӯ human   в”Ӯ   в”Ӯ freely, в”Ӯ</span></span>
<span class="line"><span>в”Ӯ command в”Ӯ   в”Ӯ executesв”Ӯ   в”Ӯ approvesв”Ӯ   в”Ӯ reviews в”Ӯ   в”Ӯ reports в”Ӯ</span></span>
<span class="line"><span>в”Ӯ         в”Ӯ   в”Ӯ         в”Ӯ   в”Ӯ then    в”Ӯ   в”Ӯ after   в”Ӯ   в”Ӯ results в”Ӯ</span></span>
<span class="line"><span>в”Ӯ         в”Ӯ   в”Ӯ         в”Ӯ   в”Ӯ agent   в”Ӯ   в”Ӯ         в”Ӯ   в”Ӯ         в”Ӯ</span></span>
<span class="line"><span>в”Ӯ         в”Ӯ   в”Ӯ         в”Ӯ   в”Ӯ executesв”Ӯ   в”Ӯ         в”Ӯ   в”Ӯ         в”Ӯ</span></span>
<span class="line"><span>в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ   в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ   в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ   в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ   в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ</span></span>
<span class="line"><span>  Aider         Copilot       Claude Code     Codex           CI/CD</span></span>
<span class="line"><span>  (suggest)     Chat          (plan mode)     (full-auto)     Headless</span></span></code></pre></div><p><strong>Different tasks require different levels of oversight:</strong></p><table tabindex="0"><thead><tr><th>Task Type</th><th>Appropriate Oversight</th><th>Why</th></tr></thead><tbody><tr><td>Reading files</td><td>None</td><td>No side effects</td></tr><tr><td>Editing source code</td><td>Session-scoped approval</td><td>Reversible via git</td></tr><tr><td>Running tests</td><td>Auto-approve</td><td>Safe, read-mostly</td></tr><tr><td>Installing packages</td><td>Per-action prompt</td><td>Modifies environment</td></tr><tr><td>Executing shell cmds</td><td>Risk-based prompt</td><td>Unbounded side effects</td></tr><tr><td>Git push / deploy</td><td>Always prompt</td><td>Affects shared state</td></tr><tr><td>File deletion</td><td>Always prompt + preview</td><td>Potentially irreversible</td></tr><tr><td>Network requests</td><td>Always prompt</td><td>Data exfiltration risk</td></tr></tbody></table><p><strong>The key challenge:</strong> finding the balance where the agent is productive enough to be useful but constrained enough to be safe. Too many prompts вҶ’ prompt fatigue вҶ’ users click &quot;allow all&quot; вҶ’ safety theater. Too few prompts вҶ’ unreviewed destructive actions вҶ’ real damage.</p><hr><h2 id="core-pattern-categories" tabindex="-1">Core Pattern Categories <a class="header-anchor" href="#core-pattern-categories" aria-label="Permalink to &quot;Core Pattern Categories&quot;">вҖӢ</a></h2><p>This research folder explores eight interconnected pattern categories. Each has a dedicated deep-dive document.</p><h3 id="_1-permission-prompts" tabindex="-1">1. Permission Prompts <a class="header-anchor" href="#_1-permission-prompts" aria-label="Permalink to &quot;1. Permission Prompts&quot;">вҖӢ</a></h3><p><strong>The primary mechanism for human oversight.</strong> How agents ask for permission before performing potentially dangerous actionsвҖ”and how they avoid asking too often.</p><p>рҹ“„ <strong><a href="./permission-prompts.html">permission-prompts.md</a></strong></p><p>Key findings across agents:</p><ul><li>Claude Code uses a <strong>5-mode permission system</strong> with glob-pattern rules and 3-layer defense</li><li>Codex implements a <strong>3-valued execution policy engine</strong> (Allow/Prompt/Forbidden) with MDM</li><li>Goose runs a <strong>4-inspector pipeline</strong> including AI-powered smart approval</li><li>OpenCode uses <strong>Go channel synchronization</strong> for async permission flow</li><li>Gemini CLI uses an <strong>event-driven confirmation bus</strong> with multi-tier sandboxing</li></ul><h3 id="_2-plan-and-confirm" tabindex="-1">2. Plan and Confirm <a class="header-anchor" href="#_2-plan-and-confirm" aria-label="Permalink to &quot;2. Plan and Confirm&quot;">вҖӢ</a></h3><p><strong>Showing plans before executing.</strong> Agents that generate a plan, present it for review, and only execute after human approval. This inverts the typical &quot;act first, ask forgiveness later&quot; pattern.</p><p>рҹ“„ <strong><a href="./plan-and-confirm.html">plan-and-confirm.md</a></strong></p><p>Key approaches: Claude Code&#39;s <code>plan</code> mode, Codex&#39;s structured plan output, Aider&#39;s architect mode with separate planning and coding models, and Goose&#39;s plan-based tool use.</p><h3 id="_3-interactive-debugging" tabindex="-1">3. Interactive Debugging <a class="header-anchor" href="#_3-interactive-debugging" aria-label="Permalink to &quot;3. Interactive Debugging&quot;">вҖӢ</a></h3><p><strong>Collaborative debugging sessions.</strong> When something goes wrong, how do agents and humans work together to diagnose and fix the problem? This covers breakpoint-aware agents, error-driven loops, and conversational debugging.</p><p>рҹ“„ <strong><a href="./interactive-debugging.html">interactive-debugging.md</a></strong></p><h3 id="_4-feedback-loops" tabindex="-1">4. Feedback Loops <a class="header-anchor" href="#_4-feedback-loops" aria-label="Permalink to &quot;4. Feedback Loops&quot;">вҖӢ</a></h3><p><strong>How agents learn from corrections.</strong> When a human rejects an action, edits agent output, or provides explicit feedbackвҖ”how does that information propagate? Covers session-level learning, memory files (CLAUDE.md, .goosehints), and preference persistence.</p><p>рҹ“„ <strong><a href="./feedback-loops.html">feedback-loops.md</a></strong></p><h3 id="_5-undo-and-rollback" tabindex="-1">5. Undo and Rollback <a class="header-anchor" href="#_5-undo-and-rollback" aria-label="Permalink to &quot;5. Undo and Rollback&quot;">вҖӢ</a></h3><p><strong>Recovering from mistakes.</strong> Git as the universal undo mechanism, checkpoint systems, snapshot-based rollback, and the design principle that &quot;undo &gt; prevent.&quot;</p><p>рҹ“„ <strong><a href="./undo-and-rollback.html">undo-and-rollback.md</a></strong></p><p>Key insight: every agent studied uses git as its primary undo mechanism. Some (Claude Code, Codex) create automatic checkpoints. Others rely on the user&#39;s existing git workflow.</p><h3 id="_6-trust-levels" tabindex="-1">6. Trust Levels <a class="header-anchor" href="#_6-trust-levels" aria-label="Permalink to &quot;6. Trust Levels&quot;">вҖӢ</a></h3><p><strong>Graduated autonomy.</strong> How agents progress from restricted to autonomous operation. Covers per-session trust escalation, persistent trust rules, organizational trust policies, and the challenge of trust revocation.</p><p>рҹ“„ <strong><a href="./trust-levels.html">trust-levels.md</a></strong></p><h3 id="_7-ux-patterns" tabindex="-1">7. UX Patterns <a class="header-anchor" href="#_7-ux-patterns" aria-label="Permalink to &quot;7. UX Patterns&quot;">вҖӢ</a></h3><p><strong>Terminal UX for human-agent interaction.</strong> The TUI frameworks, rendering strategies, keyboard interactions, and visual design patterns that make HITL interactions smooth in a terminal environment.</p><p>рҹ“„ <strong><a href="./ux-patterns.html">ux-patterns.md</a></strong></p><p>Covers: Ink (React for terminals), Bubble Tea, charm/lipgloss, streaming markdown renderers, diff viewers, permission dialogs, and progress indicators.</p><h3 id="_8-agent-comparison" tabindex="-1">8. Agent Comparison <a class="header-anchor" href="#_8-agent-comparison" aria-label="Permalink to &quot;8. Agent Comparison&quot;">вҖӢ</a></h3><p><strong>Cross-agent comparison matrix.</strong> A systematic comparison of HITL features across all 11 agents studied, with scoring rubrics and architectural trade-off analysis.</p><p>рҹ“„ <strong><a href="./agent-comparison.html">agent-comparison.md</a></strong></p><hr><h2 id="key-insights-from-research" tabindex="-1">Key Insights from Research <a class="header-anchor" href="#key-insights-from-research" aria-label="Permalink to &quot;Key Insights from Research&quot;">вҖӢ</a></h2><p>After analyzing 11 coding agents, these patterns emerge:</p><h3 id="_1-permission-fatigue-is-real" tabindex="-1">1. Permission Fatigue Is Real <a class="header-anchor" href="#_1-permission-fatigue-is-real" aria-label="Permalink to &quot;1. Permission Fatigue Is Real&quot;">вҖӢ</a></h3><p>Too many prompts degrades UX. Users who are prompted for every file edit start clicking &quot;allow&quot; reflexivelyвҖ”defeating the purpose of the prompt. The best agents use <strong>risk-based prompting</strong>: only interrupt for genuinely dangerous actions.</p><h3 id="_2-git-is-the-universal-undo-mechanism" tabindex="-1">2. Git Is the Universal Undo Mechanism <a class="header-anchor" href="#_2-git-is-the-universal-undo-mechanism" aria-label="Permalink to &quot;2. Git Is the Universal Undo Mechanism&quot;">вҖӢ</a></h3><p>Every agent studied uses git as its primary safety net. Some create automatic checkpoints before changes. The implication: agents should ensure they&#39;re operating in a git repo and should refuse destructive operations outside one.</p><h3 id="_3-plan-first-approaches-improve-outcomes" tabindex="-1">3. Plan-First Approaches Improve Outcomes <a class="header-anchor" href="#_3-plan-first-approaches-improve-outcomes" aria-label="Permalink to &quot;3. Plan-First Approaches Improve Outcomes&quot;">вҖӢ</a></h3><p>Agents that show a plan before executing (Claude Code&#39;s plan mode, Aider&#39;s architect mode) produce better results. The plan serves as both a review checkpoint and a way to align the agent&#39;s understanding with the user&#39;s intent.</p><h3 id="_4-trust-should-be-graduated-not-binary" tabindex="-1">4. Trust Should Be Graduated, Not Binary <a class="header-anchor" href="#_4-trust-should-be-graduated-not-binary" aria-label="Permalink to &quot;4. Trust Should Be Graduated, Not Binary&quot;">вҖӢ</a></h3><p>Binary &quot;allow all&quot; / &quot;deny all&quot; is insufficient. The best systems offer per-tool, per-path, and per-session trust scoping. Claude Code&#39;s glob-pattern permission rules and Codex&#39;s policy amendment system exemplify this.</p><h3 id="_5-the-best-ux-is-invisible-until-needed" tabindex="-1">5. The Best UX Is Invisible Until Needed <a class="header-anchor" href="#_5-the-best-ux-is-invisible-until-needed" aria-label="Permalink to &quot;5. The Best UX Is Invisible Until Needed&quot;">вҖӢ</a></h3><p>Permission prompts should be unobtrusive for safe actions and prominent for dangerous ones. The UI should not interrupt flow for read-only operations. Streaming output should feel natural, not jarring.</p><h3 id="_6-non-interactive-mode-is-essential-for-ci-cd" tabindex="-1">6. Non-Interactive Mode Is Essential for CI/CD <a class="header-anchor" href="#_6-non-interactive-mode-is-essential-for-ci-cd" aria-label="Permalink to &quot;6. Non-Interactive Mode Is Essential for CI/CD&quot;">вҖӢ</a></h3><p>Every serious agent supports a headless mode for automation. The permission model must degrade gracefully: from interactive prompts вҶ’ pre-configured policies вҶ’ full bypass with audit logging.</p><h3 id="_7-proactive-assistance-is-an-emerging-pattern" tabindex="-1">7. Proactive Assistance Is an Emerging Pattern <a class="header-anchor" href="#_7-proactive-assistance-is-an-emerging-pattern" aria-label="Permalink to &quot;7. Proactive Assistance Is an Emerging Pattern&quot;">вҖӢ</a></h3><p>Rather than waiting for commands, advanced agents suggest fixes, propose refactors, and anticipate needs. This inverts the HITL model: instead of &quot;agent proposes, human approves,&quot; it becomes &quot;agent observes, agent suggests, human accepts.&quot;</p><h3 id="_8-defense-in-depth-beats-any-single-layer" tabindex="-1">8. Defense-in-Depth Beats Any Single Layer <a class="header-anchor" href="#_8-defense-in-depth-beats-any-single-layer" aria-label="Permalink to &quot;8. Defense-in-Depth Beats Any Single Layer&quot;">вҖӢ</a></h3><p>The most robust agents layer multiple protection mechanisms: permission prompts + OS sandboxing + hook systems + git checkpoints. No single layer is sufficient.</p><hr><h2 id="agents-analyzed" tabindex="-1">Agents Analyzed <a class="header-anchor" href="#agents-analyzed" aria-label="Permalink to &quot;Agents Analyzed&quot;">вҖӢ</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Language</th><th>Permission Model</th><th>Plan Mode</th><th>Undo Mechanism</th><th>TUI Framework</th></tr></thead><tbody><tr><td>Claude Code</td><td>TypeScript</td><td>5-mode + glob rules</td><td>вң… plan</td><td>Git checkpoint</td><td>Ink (React)</td></tr><tr><td>Codex</td><td>TypeScript</td><td>3-valued policy engine</td><td>вң… plan</td><td>Git checkpoint</td><td>Ink (React)</td></tr><tr><td>Goose</td><td>Rust</td><td>4-inspector pipeline</td><td>вң… plan</td><td>Git undo</td><td>Ratatui</td></tr><tr><td>Aider</td><td>Python</td><td>Minimal (auto-approve)</td><td>вң… architect</td><td>Git auto-commit</td><td>Prompt Toolkit</td></tr><tr><td>OpenCode</td><td>Go</td><td>Channel-based sync</td><td>вқҢ</td><td>Git diff</td><td>Bubble Tea</td></tr><tr><td>Gemini CLI</td><td>TypeScript</td><td>Event-driven bus</td><td>вқҢ</td><td>Git checkpoint</td><td>Ink (React)</td></tr><tr><td>ForgeCode</td><td>TypeScript</td><td>Session-scoped</td><td>вқҢ</td><td>Git stash</td><td>Ink (React)</td></tr><tr><td>Warp</td><td>Rust</td><td>Inline confirmation</td><td>вң… plan</td><td>Terminal session</td><td>Custom Rust TUI</td></tr><tr><td>OpenHands</td><td>Python</td><td>Full sandbox</td><td>вң… plan</td><td>Container snapshot</td><td>Web UI</td></tr><tr><td>Droid</td><td>TypeScript</td><td>Configurable</td><td>вң… plan</td><td>Git</td><td>Custom TUI</td></tr><tr><td>Junie</td><td>Kotlin</td><td>IDE-integrated</td><td>вң… plan</td><td>IDE undo</td><td>IntelliJ UI</td></tr></tbody></table><hr><h2 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design Principles&quot;">вҖӢ</a></h2><p>These principles emerge from studying what works across agents:</p><h3 id="_1-minimize-interruption-maximize-safety" tabindex="-1">1. Minimize Interruption, Maximize Safety <a class="header-anchor" href="#_1-minimize-interruption-maximize-safety" aria-label="Permalink to &quot;1. Minimize Interruption, Maximize Safety&quot;">вҖӢ</a></h3><p>The goal is not to prompt for everythingвҖ”it&#39;s to prompt for the right things. Read-only operations should never require approval. Reversible operations should use session-scoped approval. Only truly dangerous, irreversible actions should prompt every time.</p><h3 id="_2-progressive-disclosure-of-complexity" tabindex="-1">2. Progressive Disclosure of Complexity <a class="header-anchor" href="#_2-progressive-disclosure-of-complexity" aria-label="Permalink to &quot;2. Progressive Disclosure of Complexity&quot;">вҖӢ</a></h3><p>New users see simple &quot;allow/deny&quot; prompts. Power users can configure glob patterns, per-tool policies, and organizational rules. The permission system grows with the user.</p><h3 id="_3-sensible-defaults-with-escape-hatches" tabindex="-1">3. Sensible Defaults with Escape Hatches <a class="header-anchor" href="#_3-sensible-defaults-with-escape-hatches" aria-label="Permalink to &quot;3. Sensible Defaults with Escape Hatches&quot;">вҖӢ</a></h3><p>Out of the box, the agent should be safe. Users who understand the risks can opt into more autonomy. The default should never be &quot;allow all.&quot;</p><h3 id="_4-undo-prevent" tabindex="-1">4. Undo &gt; Prevent <a class="header-anchor" href="#_4-undo-prevent" aria-label="Permalink to &quot;4. Undo &gt; Prevent&quot;">вҖӢ</a></h3><p>It&#39;s better to let an action happen and provide easy undo than to block the action entirely. Git checkpoints, file snapshots, and container rollbacks all embody this principle.</p><h3 id="_5-context-preservation-across-interactions" tabindex="-1">5. Context Preservation Across Interactions <a class="header-anchor" href="#_5-context-preservation-across-interactions" aria-label="Permalink to &quot;5. Context Preservation Across Interactions&quot;">вҖӢ</a></h3><p>When a user approves a pattern (e.g., &quot;allow npm test&quot;), that approval should persist at the right scopeвҖ”session, project, or global. Re-prompting for the same action is friction without safety benefit.</p><h3 id="_6-earn-trust-through-demonstrated-reliability" tabindex="-1">6. Earn Trust Through Demonstrated Reliability <a class="header-anchor" href="#_6-earn-trust-through-demonstrated-reliability" aria-label="Permalink to &quot;6. Earn Trust Through Demonstrated Reliability&quot;">вҖӢ</a></h3><p>An agent that consistently makes good suggestions earns the right to more autonomy. This can be explicit (user grants permissions) or implicit (agent tracks its success rate).</p><h3 id="_7-fail-open-for-reads-fail-closed-for-writes" tabindex="-1">7. Fail Open for Reads, Fail Closed for Writes <a class="header-anchor" href="#_7-fail-open-for-reads-fail-closed-for-writes" aria-label="Permalink to &quot;7. Fail Open for Reads, Fail Closed for Writes&quot;">вҖӢ</a></h3><p>When in doubt about whether to prompt: if the action only reads state, don&#39;t prompt. If the action modifies state, prompt. This simple heuristic handles most edge cases correctly.</p><h3 id="_8-audit-everything" tabindex="-1">8. Audit Everything <a class="header-anchor" href="#_8-audit-everything" aria-label="Permalink to &quot;8. Audit Everything&quot;">вҖӢ</a></h3><p>Even when an action is auto-approved, log it. Enterprise environments need audit trails. Users debugging unexpected behavior need to know what the agent did and why.</p><hr><h2 id="research-methodology" tabindex="-1">Research Methodology <a class="header-anchor" href="#research-methodology" aria-label="Permalink to &quot;Research Methodology&quot;">вҖӢ</a></h2><h3 id="sources" tabindex="-1">Sources <a class="header-anchor" href="#sources" aria-label="Permalink to &quot;Sources&quot;">вҖӢ</a></h3><ul><li><strong>Open-source codebases</strong>: Direct analysis of agent source code on GitHub</li><li><strong>Documentation</strong>: Official docs, READMEs, architecture guides</li><li><strong>Configuration schemas</strong>: Permission configs, policy files, settings schemas</li><li><strong>User experience</strong>: Terminal recordings, UX flows, interaction patterns</li></ul><h3 id="analysis-approach" tabindex="-1">Analysis Approach <a class="header-anchor" href="#analysis-approach" aria-label="Permalink to &quot;Analysis Approach&quot;">вҖӢ</a></h3><p>For each agent, we examined:</p><ol><li><strong>Permission architecture</strong>: How permissions are defined, stored, and enforced</li><li><strong>UX flow</strong>: What the user sees when a permission check fires</li><li><strong>Configurability</strong>: How users customize the permission model</li><li><strong>Automation support</strong>: How the permission model works in headless/CI mode</li><li><strong>Safety layers</strong>: Defense-in-depth beyond just permission prompts</li></ol><h3 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">вҖӢ</a></h3><ul><li>Analysis is based on publicly available source code as of mid-2025</li><li>Proprietary agents (Cursor, Windsurf) were not analyzed at source level</li><li>Agent behavior may differ between versions</li></ul><hr><h2 id="file-index" tabindex="-1">File Index <a class="header-anchor" href="#file-index" aria-label="Permalink to &quot;File Index&quot;">вҖӢ</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Description</th></tr></thead><tbody><tr><td><a href="./">README.md</a></td><td>This fileвҖ”overview of the research folder</td></tr><tr><td><a href="./permission-prompts.html">permission-prompts.md</a></td><td>How agents ask for permission before actions</td></tr><tr><td><a href="./plan-and-confirm.html">plan-and-confirm.md</a></td><td>Plan presentation and approval workflows</td></tr><tr><td><a href="./interactive-debugging.html">interactive-debugging.md</a></td><td>Collaborative human-agent debugging sessions</td></tr><tr><td><a href="./feedback-loops.html">feedback-loops.md</a></td><td>How agents learn from human corrections</td></tr><tr><td><a href="./undo-and-rollback.html">undo-and-rollback.md</a></td><td>Recovering from agent mistakes via git and snapshots</td></tr><tr><td><a href="./trust-levels.html">trust-levels.md</a></td><td>Graduated autonomy and trust escalation patterns</td></tr><tr><td><a href="./ux-patterns.html">ux-patterns.md</a></td><td>Terminal UX design for human-agent interaction</td></tr><tr><td><a href="./agent-comparison.html">agent-comparison.md</a></td><td>Cross-agent comparison matrix and scoring</td></tr></tbody></table><hr><h2 id="how-to-use-this-research" tabindex="-1">How to Use This Research <a class="header-anchor" href="#how-to-use-this-research" aria-label="Permalink to &quot;How to Use This Research&quot;">вҖӢ</a></h2><p><strong>If you&#39;re building a coding agent:</strong> Start with <a href="./permission-prompts.html">permission-prompts.md</a> for the core safety mechanism, then <a href="./trust-levels.html">trust-levels.md</a> for graduated autonomy, and <a href="./ux-patterns.html">ux-patterns.md</a> for terminal interaction design.</p><p><strong>If you&#39;re evaluating agents:</strong> Start with <a href="./agent-comparison.html">agent-comparison.md</a> for the comparison matrix, then dive into specific pattern files for areas that matter most to your use case.</p><p><strong>If you&#39;re interested in the design space:</strong> Read this README for the overview, then explore pattern files in any order. Each is self-contained with cross-references to related patterns.</p><hr><p><em>Research conducted as part of the broader coding agents architecture study. All analysis is based on publicly available open-source code and documentation.</em></p>`,106)])])}const m=t(o,[["render",r]]);export{u as __pageData,m as default};
